// src/components/Dashboard.js
import React from 'react';
import './Dashboard.css';

const Dashboard = () => {
  // Obtém a data atual
  const today = new Date();
  const options = { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' };
  const formattedDate = today.toLocaleDateString('pt-BR', options); // Formata a data para o português

  return (
    <div className="dashboard">
      <div className="dashboard-item">
        <h2>Agenda</h2>
        <div className="dashboard-content">{formattedDate}</div> {/* Exibe a data formatada */}
      </div>
      <div className="dashboard-item">
        <h2>Tarefas</h2>
        <div className="dashboard-content">1 Total</div>
      </div>
      <div className="dashboard-item">
        <h2>Intimações</h2>
        <div className="dashboard-content">10 Total</div>
      </div>
      <div className="dashboard-item">
        <h2>Andamentos</h2>
        <div className="dashboard-content">0 Total</div>
      </div>
      <div className="dashboard-item">
        <h2>Audiências</h2>
        <div className="dashboard-content">1 Total</div>
      </div>
      <div className="dashboard-item">
        <h2>Compromissos</h2>
        <div className="dashboard-content">0 Total</div>
      </div>
    </div>
  );
};

export default Dashboard;
